import{c as r,Q as o,j as e,m as a}from"./chunks/framework.hhGiamYR.js";const q=JSON.parse('{"title":"马基雅维利的命运概念是一种概率论","description":"","frontmatter":{"title":"马基雅维利的命运概念是一种概率论","date":"2026-05-23T00:00:00.000Z"},"headers":[],"relativePath":"research/fortune-probability.md","filePath":"research/fortune-probability.md"}'),l={name:"research/fortune-probability.md"};function i(d,t,n,u,s,h){return o(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="马基雅维利的-命运-概念是一种概率论" tabindex="-1">马基雅维利的&quot;命运&quot;概念是一种概率论 <a class="header-anchor" href="#马基雅维利的-命运-概念是一种概率论" aria-label="Permalink to &quot;马基雅维利的&quot;命运&quot;概念是一种概率论&quot;">​</a></h1><blockquote><p>2026-05-23 · 研究笔记</p></blockquote><hr><h2 id="说法的来源" tabindex="-1">说法的来源 <a class="header-anchor" href="#说法的来源" aria-label="Permalink to &quot;说法的来源&quot;">​</a></h2><p>《君主论》第 25 章是最著名的段落：</p><blockquote><p><em>&quot;我不是不知道，许多人过去和现在都认为，世界上的事情是由命运和上帝支配的，人们无法靠自己的审慎来修正……但为了不把我们的自由意志完全消灭，我认为：命运是我们半个行动的主宰，但留下其余一半——或几乎一半——由我们支配。&quot;</em></p></blockquote><p>这就是那个著名的 <strong>50/50 法则</strong>。人们通常把它当作一句豪迈的格言来引用，但很少有人从概率框架的角度来读它。</p><h2 id="为什么说它是概率论" tabindex="-1">为什么说它是概率论 <a class="header-anchor" href="#为什么说它是概率论" aria-label="Permalink to &quot;为什么说它是概率论&quot;">​</a></h2><p>马基雅维利在第 25 章里做了一件非常现代的事：他在量化不确定性。</p><table tabindex="0"><thead><tr><th>传统观念</th><th>马基雅维利的版本</th></tr></thead><tbody><tr><td>命运是神的力量，不可抗拒</td><td>命运是概率分布，约 50% 不确定</td></tr><tr><td>人只能服从神意</td><td>人可以影响另一半</td></tr><tr><td>道德决定结果</td><td><strong>准备</strong>（virtù的体现）决定结果</td></tr></tbody></table><p>他说&quot;大约一半&quot;——不是精确的 50%，而是一个估计。这种语言本身就表明他在<strong>建模</strong>，不是在布道。</p><p>然后他打了一个比喻：</p><blockquote><p><em>&quot;我将命运比作那些暴虐的河流之一：当它发怒时，淹没平原，推倒树木和房屋……但尽管它如此凶猛，人们在风平浪静时仍然可以修筑堤坝和渠道，以便下次洪水来临时，水可以流入运河，不至于如此泛滥成灾。&quot;</em></p></blockquote><p>翻译成现代语言：</p><ul><li><strong>洪水 = 尾部风险（tail risk）</strong></li><li><strong>堤坝和渠道 = 风险对冲和冗余系统</strong></li><li><strong>风平浪静时修筑 = 在非危机时期建立抗脆弱性</strong></li></ul><p>这不是格言，这是风险管理框架。</p><h2 id="跟《论李维》里的-轮子-说法对照" tabindex="-1">跟《论李维》里的&quot;轮子&quot;说法对照 <a class="header-anchor" href="#跟《论李维》里的-轮子-说法对照" aria-label="Permalink to &quot;跟《论李维》里的&quot;轮子&quot;说法对照&quot;">​</a></h2><p>在《论李维》中，他把命运比作一个<strong>转动的轮子</strong>：</p><blockquote><p><em>&quot;命运像一个轮子，谁在上面谁就被高高抬起，但转瞬之间又被压到底下。&quot;</em></p></blockquote><p>轮子隐喻被解读为&quot;宿命论&quot;——你在轮子上，迟早会被压到。但如果你把轮子看作一个<strong>周期性概率模型</strong>，解读完全不同：</p><ul><li>位置在高处 ≠ 永恒安全</li><li>位置在低处 ≠ 永恒危险</li><li>关键不是&quot;你此刻在轮子哪个位置&quot;，而是<strong>你为轮子转动准备了什么</strong></li></ul><p>轮子的转动频率不是随机的——它受政治结构、军事力量、外交联盟这些<strong>德能可以干预的变量</strong>影响。换句话说：轮子是一个马尔可夫链，德能是转移概率的调节器。</p><h2 id="为什么这个解读重要" tabindex="-1">为什么这个解读重要 <a class="header-anchor" href="#为什么这个解读重要" aria-label="Permalink to &quot;为什么这个解读重要&quot;">​</a></h2><p>如果把马基雅维利读成一个&quot;命运可以被操控&quot;的乐观主义者，会误解他。他不是在说&quot;只要你有德能，命运就会听你的&quot;。他是在说&quot;你只能影响一半，但那一半足够让你活下去&quot;。</p><p>一个没有概率直觉的人读到第 25 章会觉得：&quot;好，只要我足够 bold，命运就会站在我这边。&quot;但马基雅维利的原话是：</p><blockquote><p><em>&quot;机运是一个女人，如果想要让她臣服，就必须打她、撞击她。&quot;</em></p></blockquote><p>这句话被现代读者斥为厌女。但如果从概率角度读：他不是在讨论性别，而是在讨论<strong>大胆行动的期望值</strong>——保守者在概率上总是失败，因为机会窗口是短暂的。你不需要每次都赢（那不可能），但你需要在你能够影响的那一半里，采取一个最大化期望值的策略。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>经典解读</th><th>概率论解读</th></tr></thead><tbody><tr><td>命运占一半，人的努力占一半</td><td>方差约 50%，可控方差约 50%</td></tr><tr><td>大胆胜过谨慎</td><td>高方差策略在机会窗口有限时优于低方差策略</td></tr><tr><td>堤坝是比喻</td><td>堤坝是冗余系统，降低尾部风险</td></tr><tr><td>轮子是宿命</td><td>轮子是周期模型，德能调节转移概率</td></tr></tbody></table><hr><p><em>相关原文：<a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/en/XXV-chapter.md" target="_blank" rel="noreferrer">《君主论》第25章：机运在人类事务中有多大力量</a> · <a href="https://niflhum.top/machiavelli-library/library/machiavelli/discourses/" target="_blank" rel="noreferrer">《论李维》（Discourses）</a></em></p>',31)])])}const b=r(l,[["render",i]]);export{q as __pageData,b as default};
